import {
  Route,
  Navigate,
  createBrowserRouter,
  createRoutesFromElements,
  RouterProvider,
} from 'react-router-dom';
import * as Sentry from '@sentry/react';

import { appPaths } from 'Shared/constants/appPaths';

import OnlyPrivate from './OnlyPrivate';
import OnlyPublic from './OnlyPublic';
import TransactionsPage from '../../pages/transactions/TransactionsPage';
import BudgetPage from '../../pages/budget/BudgetPage';
import BudgetsPage from '../../pages/budgets/BudgetsPage';
import BankAccountsPage from '../../pages/bankAccounts/BankAccountsPage';
import UserCategoryPage from '../../pages/userCatigory/UserCategoryPage';
import RegistrationPage from '../../pages/registration/RegistrationPage';
import LoginPage from '../../pages/login/LoginPage';
import AuthPage from '../../pages/auth/AuthPage';
import LogoutPage from '../../pages/logout/LogoutPage';
import ProfilePage from '../../pages/profile/ProfilePage';
import { GlobalErrorBoundary } from '../errorBoundery/GlobalErrorBoundary';

const sentryCreateBrowserRouter =
  Sentry.wrapCreateBrowserRouterV6(createBrowserRouter);

const router = sentryCreateBrowserRouter(
  createRoutesFromElements(
    <Route
      path={appPaths.INDEX.getPath()}
      errorElement={<GlobalErrorBoundary />}
    >
      <Route element={<OnlyPrivate />}>
        <Route
          index
          element={<Navigate to={appPaths.BUDGETS.getPath()} />}
        />
        <Route
          path={appPaths.TRANSACTIONS.getPath()}
          element={<TransactionsPage />}
        />
        <Route
          path={appPaths.BUDGET.getPath()}
          element={<BudgetPage />}
        />
        <Route
          path={appPaths.BUDGETS.getPath()}
          element={<BudgetsPage />}
        />
        <Route
          path={appPaths.BANK_INSTITUTION.getPath()}
          element={<BankAccountsPage />}
        />
        <Route
          path={appPaths.USER_CATEGORY.getPath()}
          element={<UserCategoryPage />}
        />
        <Route
          path={appPaths.PROFILE.getPath()}
          element={<ProfilePage />}
        />
      </Route>

      <Route element={<OnlyPublic />}>
        <Route
          path={appPaths.REGISTRATION.getPath()}
          element={<RegistrationPage />}
        />
        <Route
          path={appPaths.LOGIN.getPath()}
          element={<LoginPage />}
        />
        <Route
          path={appPaths.AUTH.getPath()}
          element={<AuthPage />}
        />
      </Route>

      <Route
        path="/logout"
        element={<LogoutPage />}
      />
    </Route>,
  ),
);

const AppRoutes = () => <RouterProvider router={router} />;

export default AppRoutes;

