import { signal } from '@preact/signals-core';

import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { NotificationT } from 'Shared/types/NotificationT';
import { ModalT } from 'Components/modal/ModalT';
import { SidebarT } from 'Components/sidebar/types/SidebarT';
import { SaveRemovalT } from 'Shared/types/SaveRemovalT';

export const globalStore = {
  [GlobalStoreFieldE.AUTH_TOKEN]: signal<string | null>(null),
  [GlobalStoreFieldE.NOTIFICATIONS]: signal<NotificationT[]>([]),
  [GlobalStoreFieldE.MODALS]: signal<ModalT[]>([]),
  [GlobalStoreFieldE.IDS_LIST]: signal<SaveRemovalT>({}),
  [GlobalStoreFieldE.SIDEBAR]: signal<SidebarT[]>([]),
};

if (process.env.NODE_ENV === 'development' && typeof window !== 'undefined') {
  window.globalStore = globalStore;
}

export type GlobalStoreT = typeof globalStore;

